class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved the "Discriminator" property
        // name via HasDiscriminator("Discriminator") in OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 removed synchronous APIs (ToList, First, Single, etc.) for
        // the Cosmos provider. All queries must use async equivalents.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

